/**
 * Email Utilities Tests
 *
 * Tests for email processing utility functions including domain extraction,
 * HTML text extraction, and email body text extraction.
 */

import {
  extractDomainFromEmail,
  extractTextFromHtml,
  extractEmailBodyText,
  domainMatches,
  findMatchingDomain,
  findMatchingKeywords,
  findMatchingPrefix,
  isValidEmailFormat,
  normalizeEmail,
} from '../../src/utils/email-utils';

import { EmailMessage } from '../../src/types/email-message';

describe('Email Utilities', () => {
  describe('extractEmailBodyText', () => {
    it('should return plain text body when available', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: 'This is plain text',
        bodyHtml: '<p>This is HTML</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('This is plain text');
    });

    it('should extract text from HTML body when plain text not available', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: '',
        bodyHtml: '<p>Hello <b>world</b>!</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toContain('Hello');
      expect(result).toContain('world');
      expect(result).not.toContain('<');
      expect(result).not.toContain('>');
    });

    it('should handle undefined bodyPlain', () => {
      const email: Partial<EmailMessage> = {
        bodyHtml: '<p>HTML content</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('HTML content');
    });

    it('should handle undefined bodyHtml', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: 'Plain text content',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('Plain text content');
    });

    it('should return empty string when both bodies are empty', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: '',
        bodyHtml: '',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('');
    });

    it('should return empty string when both bodies are undefined', () => {
      const email: Partial<EmailMessage> = {};

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('');
    });

    it('should trim whitespace from plain text', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: '  Content with spaces  ',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('Content with spaces');
    });

    it('should handle complex HTML with multiple tags', () => {
      const email: Partial<EmailMessage> = {
        bodyHtml: `
          <html>
            <body>
              <p>Paragraph 1</p>
              <div>Div content</div>
              <span>Span content</span>
            </body>
          </html>
        `,
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toContain('Paragraph 1');
      expect(result).toContain('Div content');
      expect(result).toContain('Span content');
    });

    it('should prefer plain text even if it is just whitespace', () => {
      const email: Partial<EmailMessage> = {
        bodyPlain: '   ',
        bodyHtml: '<p>HTML content</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe(''); // Trimmed whitespace
    });

    it('should handle HTML entities correctly', () => {
      const email: Partial<EmailMessage> = {
        bodyHtml: '<p>Price: &lt;$100&gt; &amp; free shipping</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('Price: <$100> & free shipping');
    });

    it('should remove script tags from HTML', () => {
      const email: Partial<EmailMessage> = {
        bodyHtml: '<p>Content</p><script>alert("test")</script><p>More</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).not.toContain('alert');
      expect(result).toContain('Content');
      expect(result).toContain('More');
    });

    it('should normalize whitespace in HTML extraction', () => {
      const email: Partial<EmailMessage> = {
        bodyHtml: '<p>Line   1</p>   <p>Line    2</p>',
      };

      const result = extractEmailBodyText(email as EmailMessage);

      expect(result).toBe('Line 1 Line 2');
    });
  });

  describe('extractTextFromHtml', () => {
    it('should remove HTML tags', () => {
      const html = '<p>Hello <b>world</b>!</p>';
      const result = extractTextFromHtml(html);
      expect(result).toContain('Hello');
      expect(result).toContain('world');
      expect(result).not.toContain('<');
      expect(result).not.toContain('>');
    });

    it('should remove script tags and content', () => {
      const html = '<div>Before<script>alert("test")</script>After</div>';
      expect(extractTextFromHtml(html)).toBe('Before After');
    });

    it('should remove style tags and content', () => {
      const html = '<div>Content<style>.class { color: red; }</style>More</div>';
      expect(extractTextFromHtml(html)).toBe('Content More');
    });

    it('should replace HTML entities', () => {
      const html = '&lt;p&gt; &amp; &quot;quotes&quot; &#39;apostrophe&#39;';
      expect(extractTextFromHtml(html)).toBe('<p> & "quotes" \'apostrophe\'');
    });

    it('should normalize whitespace', () => {
      const html = '<p>Line   1</p>   <p>Line    2</p>';
      expect(extractTextFromHtml(html)).toBe('Line 1 Line 2');
    });

    it('should handle empty string', () => {
      expect(extractTextFromHtml('')).toBe('');
    });
  });

  describe('extractDomainFromEmail', () => {
    it('should extract domain from email address', () => {
      expect(extractDomainFromEmail('user@example.com')).toBe('example.com');
    });

    it('should convert domain to lowercase', () => {
      expect(extractDomainFromEmail('user@EXAMPLE.COM')).toBe('example.com');
    });

    it('should handle email without @ sign', () => {
      expect(extractDomainFromEmail('invalid-email')).toBe('invalid-email');
    });

    it('should handle multiple @ signs (use last one)', () => {
      expect(extractDomainFromEmail('user@name@example.com')).toBe('example.com');
    });
  });

  describe('domainMatches', () => {
    it('should match exact domains', () => {
      expect(domainMatches('example.com', 'example.com')).toBe(true);
    });

    it('should match subdomains', () => {
      expect(domainMatches('mail.example.com', 'example.com')).toBe(true);
      expect(domainMatches('noreply.mail.example.com', 'example.com')).toBe(true);
    });

    it('should not match different domains', () => {
      expect(domainMatches('example.com', 'different.com')).toBe(false);
      expect(domainMatches('example.org', 'example.com')).toBe(false);
    });

    it('should be case-insensitive', () => {
      expect(domainMatches('EXAMPLE.COM', 'example.com')).toBe(true);
      expect(domainMatches('example.com', 'EXAMPLE.COM')).toBe(true);
    });

    it('should not match partial domain names', () => {
      expect(domainMatches('fakeexample.com', 'example.com')).toBe(false);
    });
  });

  describe('findMatchingKeywords', () => {
    it('should find matching keywords case-insensitively', () => {
      const result = findMatchingKeywords('Invoice #123 due', ['invoice', 'receipt']);
      expect(result).toEqual(['invoice']);
    });

    it('should find multiple matches', () => {
      const result = findMatchingKeywords('Invoice and receipt', ['invoice', 'receipt']);
      expect(result).toEqual(['invoice', 'receipt']);
    });

    it('should return empty array when no matches', () => {
      const result = findMatchingKeywords('Hello world', ['payment', 'bill']);
      expect(result).toEqual([]);
    });

    it('should handle empty text', () => {
      const result = findMatchingKeywords('', ['keyword']);
      expect(result).toEqual([]);
    });

    it('should handle empty keywords array', () => {
      const result = findMatchingKeywords('Some text', []);
      expect(result).toEqual([]);
    });

    it('should preserve original keyword case in results', () => {
      const result = findMatchingKeywords('invoice here', ['INVOICE']);
      expect(result).toEqual(['INVOICE']);
    });
  });

  describe('findMatchingPrefix', () => {
    it('should find matching prefix case-insensitively', () => {
      const result = findMatchingPrefix('Invoice #123', ['invoice', 'receipt']);
      expect(result).toBe('invoice');
    });

    it('should return first matching prefix', () => {
      const result = findMatchingPrefix('Invoice #123', ['invoice', 'inv']);
      expect(result).toBe('invoice');
    });

    it('should return null when no match', () => {
      const result = findMatchingPrefix('Hello world', ['payment', 'bill']);
      expect(result).toBeNull();
    });

    it('should handle empty text', () => {
      const result = findMatchingPrefix('', ['prefix']);
      expect(result).toBeNull();
    });

    it('should handle empty prefixes array', () => {
      const result = findMatchingPrefix('Some text', []);
      expect(result).toBeNull();
    });
  });

  describe('isValidEmailFormat', () => {
    it('should validate correct email formats', () => {
      expect(isValidEmailFormat('user@example.com')).toBe(true);
      expect(isValidEmailFormat('test.user@example.co.uk')).toBe(true);
      expect(isValidEmailFormat('user+tag@example.com')).toBe(true);
    });

    it('should reject invalid email formats', () => {
      expect(isValidEmailFormat('invalid')).toBe(false);
      expect(isValidEmailFormat('invalid@')).toBe(false);
      expect(isValidEmailFormat('@example.com')).toBe(false);
      expect(isValidEmailFormat('user @example.com')).toBe(false);
    });
  });

  describe('normalizeEmail', () => {
    it('should convert to lowercase', () => {
      expect(normalizeEmail('USER@EXAMPLE.COM')).toBe('user@example.com');
    });

    it('should trim whitespace', () => {
      expect(normalizeEmail('  user@example.com  ')).toBe('user@example.com');
    });

    it('should handle already normalized emails', () => {
      expect(normalizeEmail('user@example.com')).toBe('user@example.com');
    });
  });
});

